def search_foods(query: str) -> list:
    if not query:
        return INDIAN_FOODS_DB
    q = query.lower()
    return [f for f in INDIAN_FOODS_DB if q in f["name"].lower()]


def get_food_by_id(fdc_id: str) -> dict | None:
    for f in INDIAN_FOODS_DB:
        if f["fdcId"] == fdc_id:
            return f
    return None
